/*
 * Geist Mono font — loaded from CDN. In production this would come from
 * the host app's font stack or be self-hosted.
 * Must precede @import "tailwindcss" because CSS @import rules must come
 * before all other statements in the compiled output.
 */
@import url("https://fonts.googleapis.com/css2?family=Geist+Mono:wght@300..900&display=swap");

@import "tailwindcss";

/*
 * Map HostBridge DesignTokens (set as CSS custom properties by AppShell)
 * into Tailwind's theme so utilities like bg-primary, text-muted, etc. work.
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. All colors resolve through
 * CSS vars so the host app can override at runtime.
 */

@theme {
  /* ── Colors ──────────────────────────────────────────────────────── */
  --color-primary: var(--color-primary, #737373);
  --color-primary-foreground: #fafafa;
  --color-secondary: var(--color-secondary, #f5f5f5);
  --color-secondary-foreground: #171717;
  --color-surface: var(--color-surface, #ffffff);
  --color-surface-raised: #fafafa;
  --color-background: var(--color-background, #ffffff);
  --color-foreground: var(--color-text, #0a0a0a);
  --color-muted: var(--color-text-muted, #717171);
  --color-muted-bg: #f5f5f5;
  --color-border: var(--color-border, #e5e5e5);
  --color-input: #e5e5e5;
  --color-ring: #a1a1a1;
  /* ── Semantic status colors (WCAG AA-validated, muted palette) ──── */
  /* Light-mode base values pass ≥4.5:1 contrast against their respective   */
  /* bg tokens. Foreground (#fafafa) passes ≥4.5:1 on each base.            */
  --color-success: var(--color-success, #3D7A4A);
  --color-success-bg: #EEF3EF;
  --color-success-border: #C7D6CB;
  --color-success-foreground: #fafafa;
  --color-warning: var(--color-warning, #7A6520);
  --color-warning-bg: #F5F2EA;
  --color-warning-border: #DDD2B8;
  --color-warning-foreground: #fafafa;
  --color-danger: var(--color-danger, #9B3B3B);
  --color-danger-bg: #F6EEEE;
  --color-danger-border: #E2CACA;
  --color-danger-foreground: #fafafa;
  /* Info/AI — CSS-only token (not in host DesignTokens contract)            */
  --color-info: var(--color-info, #4A5578);
  --color-info-bg: #EEF1F6;
  --color-info-border: #CCD3E0;
  --color-info-foreground: #fafafa;

  /* ── Typography ──────────────────────────────────────────────────── */
  --font-family-base: var(--font-family-base, "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace);
  --font-family-mono: "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;

  /* ── Radii (0rem = sharp corners everywhere) ─────────────────────── */
  --radius-sm: calc(var(--border-radius, 0rem) * 0.75);
  --radius-default: var(--border-radius, 0rem);
  --radius-md: calc(var(--border-radius, 0rem) * 1.25);
  --radius-lg: calc(var(--border-radius, 0rem) * 2);
  --radius-full: 9999px;

  /* ── Shadows (minimal — 1px y-offset, low opacity) ───────────────── */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.08);
}

/*
 * ── Dark mode ─────────────────────────────────────────────────────────
 *
 * Activated by <html data-theme="dark">. Every semantic color is remapped;
 * components pick up the change automatically through CSS vars.
 * The palette is the same neutral gray family, just inverted.
 */


